mapper.update:
UPDATE phone_verification
SET expires_at = now()
WHERE phone = #{phone}
  AND purpose = #{purpose}
  AND verified_at IS NULL

mapper.select:
SELECT id
FROM phone_verification
WHERE phone = #{phone}
  AND purpose = #{purpose}
  AND code = #{code}
  AND verified_at IS NULL
  AND expires_at >= now()
ORDER BY created_at DESC
LIMIT 1

mapper.update:
UPDATE phone_verification
SET verified_at = now()
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM phone_verification
WHERE phone = #{phone}
  AND purpose = #{purpose}
  AND verified_at IS NOT NULL
  AND verified_at >= #{since}

SELECT id
FROM point_voucher
WHERE voucher_number = #{voucherNumber}

mapper.update:
UPDATE point_voucher
SET used_amount = used_amount + #{amount},
    remaining_amount = remaining_amount - #{amount},
    updated_at = now()
WHERE id = #{id}
  AND remaining_amount >= #{amount}

mapper.delete:
DELETE FROM point_voucher_usage
WHERE voucher_id = #{voucherId}
  AND order_number = #{orderNumber}
